{"Question": "How can I create custom behavioral cohorts with complex conditions?", "Context": "I need to define custom cohorts based on multiple conditions that can't be expressed with simple operators.", "Code_Example": "from cohortanalysistools import CohortPipe, form_behavioral_cohorts

# Define custom cohort functions
def power_users(df):
    return (df['session_count'] > 20) & (df['feature_usage'] > 5) & (df['has_profile'] == True)

def casual_users(df):
    return (df['session_count'] <= 10) & (df['time_in_app'] < 30)

# Create custom cohorts
custom_cohorts = {
    'Power Users': power_users,
    'Casual Users': casual_users
}

# Apply custom cohort logic
user_segments = pipeline | form_behavioral_cohorts(
    behavior_column='session_count',  # Used for basic segmentation
    cohort_column='user_segment',
    custom_cohorts=custom_cohorts
)

# View distribution
print(user_segments.data['user_segment'].value_counts())", "Usage": "form_behavioral_cohorts(behavior_column='session_count', cohort_column='user_segment', custom_cohorts={'Power Users': power_users, 'Casual Users': casual_users})"}
